    @Metadata(description = "Path to FIX configuration file")
    private String configFile;

    @UriParam(label = "common")
    @Metadata(description = "The sender CompID")
    private String senderCompID;

    @UriParam(label = "common")
    @Metadata(description = "The target CompID")
    private String targetCompID;

