package org.apache.camel.component.fix;

import org.apache.camel.AsyncCallback;
import org.apache.camel.Exchange;
import org.apache.camel.support.DefaultAsyncProducer;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

/**
 * FIX producer for sending FIX messages.
 */
public class FixProducer extends DefaultAsyncProducer {

    private static final Logger LOG = LoggerFactory.getLogger(FixProducer.class);

    private final FixEndpoint endpoint;

    public FixProducer(FixEndpoint endpoint) {
        super(endpoint);
        this.endpoint = endpoint;
    }

    @Override
    public boolean process(Exchange exchange, AsyncCallback callback) {
        try {
            LOG.debug("Processing FIX message for session: {}", endpoint.getSessionID());

            // Get the message body
            Object body = exchange.getIn().getBody();

            // Extract FIX session information from configuration
            FixConfiguration config = endpoint.getConfiguration();

            // Set headers from configuration
            if (config.getSenderCompID() != null) {
                exchange.getIn().setHeader(FixConstants.FIX_SENDER_COMP_ID, config.getSenderCompID());
            }
            if (config.getTargetCompID() != null) {
                exchange.getIn().setHeader(FixConstants.FIX_TARGET_COMP_ID, config.getTargetCompID());
            }

            LOG.debug("FIX message body: {}", body);

            // Return success
            callback.done(false);
            return true;
        } catch (Exception e) {
            LOG.error("Error processing FIX message", e);
            exchange.setException(e);
            callback.done(false);
            return true;
        }
    }

    @Override
    protected void doStart() throws Exception {
        super.doStart();
        LOG.debug("FIX producer started for session: {}", endpoint.getSessionID());
    }

    @Override
    protected void doStop() throws Exception {
        super.doStop();
        LOG.debug("FIX producer stopped for session: {}", endpoint.getSessionID());
    }
}

